import{_ as e,o as s,c as i,a0 as o}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"Difusão Semântica de Tempo Limitado em T4","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/BOUNDED_DIFFUSION_T4.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/BOUNDED_DIFFUSION_T4.md","lastUpdated":1783623176000}'),n={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/BOUNDED_DIFFUSION_T4.md"};function t(d,a,r,c,p,l){return s(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="difusao-semantica-de-tempo-limitado-em-t4" tabindex="-1">Difusão Semântica de Tempo Limitado em T4 <a class="header-anchor" href="#difusao-semantica-de-tempo-limitado-em-t4" aria-label="Permalink to &quot;Difusão Semântica de Tempo Limitado em T4&quot;">​</a></h1><p><strong>Status</strong>: Decisão de runtime<br><strong>Data</strong>: 2026-03-24<br><strong>Documento companheiro</strong>: <code>GEOMETRIA_DE_FLUXO_T3.md</code>, <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code></p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Este documento responde a uma pergunta precisa: por que o sistema NEXUS não sofre de explosão combinatória de caminhos ao fazer difusão semântica sobre o grafo T4?</p><p>A <code>GEOMETRIA_DE_FLUXO_T3.md</code> define o que é difusão em termos conceituais — o campo induzido pela query, o custo de caminho <code>J(γ)</code>, a integral de linha sobre a malha. A <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code> define a função Hamiltoniana de stress que pesa cada aresta. Este documento explica o mecanismo de tempo limitado que torna a difusão computacionalmente viável.</p><p>A resposta não é &quot;porque limitamos o número de hops&quot;. A resposta é que três mecanismos ortogonais atuam juntos para garantir que o espaço de busca permaneça restrito mesmo em grafos grandes.</p><hr><h2 id="_1-a-semantica-de-w-q-e-condutancia-nao-trabalho" tabindex="-1">1. A semântica de <code>w_q(e)</code>: condutância, não trabalho <a class="header-anchor" href="#_1-a-semantica-de-w-q-e-condutancia-nao-trabalho" aria-label="Permalink to &quot;1. A semântica de \`w_q(e)\`: condutância, não trabalho&quot;">​</a></h2><p>O documento <code>GEOMETRIA_DE_FLUXO_T3.md</code> define <code>w_q(e)</code> como o peso contextual de uma aresta sob a query. Na formulação contínua:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>J(γ) = ∫_γ F_q(x) ds</span></span></code></pre></div><p>Na formulação discreta:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>J(γ) = Σ_{e ∈ γ} w_q(e)</span></span></code></pre></div><p>Aqui há uma distinção conceitual fundamental que a notação não torna explícita. <code>w_q(e)</code> não é trabalho. Não é energia acumulada. É <strong>condutância</strong> — a capacidade de uma aresta transferir relevância de um nó a outro.</p><p>A distinção importa porque:</p><ul><li><strong>Trabalho</strong> (ou energia) é conservado. O que é consumido em um passo não reaparece.</li><li><strong>Condutância</strong> é um coeficiente de transferência. Ela determina quanto do score de um nó flui para o nó vizinho a cada passo de Random Walk.</li></ul><p>No código (<code>main.rs:825-827</code>), <code>w</code> é calculado como:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">COALESCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">EXP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">05</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EXTRACT(EPOCH </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> COALESCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">content_date</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">last_ingested_at</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 86400</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)::float8 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> w</span></span></code></pre></div><p>Ou seja:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>w = stress × exp(-0.05 · Δt / 86400)</span></span></code></pre></div><p>Onde <code>Δt</code> é o tempo transcorrido desde a última modificação do conteúdo. A aresta perde condutância exponencialmente com a idade. Isso reflete uma escolha de design: conexões antigas transferem menos relevância, porque a geometria semântica pode ter mudado.</p><p>O stress da aresta (do Hamiltonian) é a <strong>condutância base</strong>. O fator de decaimento temporal é um <strong>atenuador</strong>. O produto é a condutância efetiva no momento atual.</p><hr><h2 id="_2-fluxo-versus-trabalho-a-equacao-de-transferencia" tabindex="-1">2. Fluxo versus trabalho: a equação de transferência <a class="header-anchor" href="#_2-fluxo-versus-trabalho-a-equacao-de-transferencia" aria-label="Permalink to &quot;2. Fluxo versus trabalho: a equação de transferência&quot;">​</a></h2><p>A <code>GEOMETRIA_DE_FLUXO_T3.md</code> usa <code>J(γ)</code> para denotar o trabalho acumulado ao longo de um caminho. Isso é consistente com a física: trabalho é força vezes deslocamento, acumulado ao longo de uma trajetória.</p><p>Mas o runtime atual não calcula <code>J(γ)</code> explicitamente. Ele computa <strong>fluxo</strong> — a taxa de transferência de score por passo do Random Walk.</p><p>No código (<code>main.rs:855-860</code>):</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> flow </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (s </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PPR_ALPHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> w) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> s_deg;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">next</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">entry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tgt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">or_insert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> flow;</span></span></code></pre></div><p>Onde:</p><ul><li><code>s</code> é o score (score de PageRank personalizado) no nó fonte</li><li><code>PPR_ALPHA</code> é o fator de teleportação (0.85)</li><li><code>w</code> é a condutância da aresta</li><li><code>s_deg</code> é o grau do nó fonte (número de arestas saindo dele)</li></ul><p>A fórmula de fluxo é:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>flow = s · α · w / deg</span></span></code></pre></div><p>Isso é a <strong>lei de Ohm para difusão semântica</strong>: a corrente (flow) é igual ao potencial (s), vezes a condutância (w), dividido pela resistência (deg). O grau do nó atua como resistência — quanto mais arestas saindo de um nó, menor a fração de score que vai para cada vizinho específico.</p><p><strong>A key insight</strong>: o fluxo <strong>não se acumula</strong> ao longo do caminho. Cada passo do Random Walk é independente. O score no nó <code>t</code> após <code>k</code> hops é a soma de todos os caminhos de comprimento <code>k</code> que terminam em <code>t</code>, mas o sistema nunca enumera esses caminhos explicitamente. Ele mantém apenas os scores nodais e aplica a matriz de transição estocástica.</p><p>Isto contrasta com <code>J(γ)</code> da <code>GEOMETRIA_DE_FLUXO_T3.md</code>, que é o trabalho total ao longo de um caminho específico. <code>J(γ)</code> seria a quantidade relevante se estivéssemos resolvendo um problema de otimização de trajetória (e.g., &quot;qual é o caminho de menor custo?&quot;). Mas para difusão de relevance, o que importa é a distribuição estacionário do Random Walk — não o custo de caminhos individuais.</p><hr><h2 id="_3-inercia-como-o-score-entra-no-modelo" tabindex="-1">3. Inércia: como o score entra no modelo <a class="header-anchor" href="#_3-inercia-como-o-score-entra-no-modelo" aria-label="Permalink to &quot;3. Inércia: como o score entra no modelo&quot;">​</a></h2><p>Na física clássica, inércia é a tendência de um corpo em movimento a permanecer em movimento. No contexto de difusão semântica, o score <code>s</code> no nó atua como <strong>energia cinética</strong> — a &quot;quantidade de movimento&quot; que o nó tem para transferir aos vizinhos.</p><p>No Hamiltonian formal (<code>FORMAL_ANALYSIS_HAMILTONIAN.md</code>), a energia de uma aresta é:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H(s, t) = max(0, ||V_t - T ⊙ V_s||² / N - δ) · √(M_s · M_t) · w</span></span></code></pre></div><p>O Hamiltonian é uma <strong>função de energia potencial</strong> (stress). Mas o que faz a difusão andar não é o stress diretamente — é o score.</p><p>O score <code>s</code> começa como a distribuição de partida (das sementes do Qdrant). A cada hop, o score se propaga pela regra:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>s_{k+1}(t) = Σ_{s → t} s_k(s) · α · w(s,t) / deg(s)</span></span></code></pre></div><p>O fator <code>(1 - α)</code> da teleportação garante que uma fração do score original (das sementes) seja reinjetada a cada passo, impedindo a distribuição de colapsar para zero ou divergir.</p><p><strong>A interpretação física</strong>: o score é a energia cinética离散 no nó. A condutância <code>w</code> é a &quot;seção transversal&quot; da aresta. O grau <code>deg</code> é a &quot;resistência total do nó&quot;. A constante <code>α = 0.85</code> é o fator de inércia — 85% da energia cinética do nó é redistribuída a cada passo; 15% é reinjeção direta das sementes.</p><hr><h2 id="_4-os-tres-mecanismos-ortogonais-que-previnem-explosao-combinatoria" tabindex="-1">4. Os três mecanismos ortogonais que previnem explosão combinatória <a class="header-anchor" href="#_4-os-tres-mecanismos-ortogonais-que-previnem-explosao-combinatoria" aria-label="Permalink to &quot;4. Os três mecanismos ortogonais que previnem explosão combinatória&quot;">​</a></h2><p>Esta é a questão central do documento. A formulação teórica de difusão sobre um grafo poderia, em princípio, explorar todos os caminhos possíveis. Em um grafo denso, o número de caminhos de comprimento <code>k</code> cresce exponencialmente com <code>k</code>. Por que isso não acontece no NEXUS?</p><h3 id="mecanismo-1-horizonte-de-hops-limitado" tabindex="-1">Mecanismo 1: Horizonte de hops limitado <a class="header-anchor" href="#mecanismo-1-horizonte-de-hops-limitado" aria-label="Permalink to &quot;Mecanismo 1: Horizonte de hops limitado&quot;">​</a></h3><p>O primeiro mecanismo é o mais direto: o sistema executa exatamente <code>PPR_MAX_HOPS = 3</code> iterações de Random Walk (<code>main.rs:812</code>).</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PPR_MAX_HOPS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> usize</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PPR_ALPHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> f64</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.85</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PPR_MIN_SCORE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> f64</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.01</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _hop </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">PPR_MAX_HOPS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span></code></pre></div><p>Três hops significam que qualquer caminho considerado tem no máximo 3 arestas. O número de caminhos de comprimento ≤ 3 a partir de <code>n</code> sementes é <code>O(n · d²)</code> onde <code>d</code> é o grau máximo do grafo — polynomial, não exponencial.</p><p>Por que 3? Porque a partir de 4 hops, a condutância efetiva cai abaixo de qualquer limiar útil. A cada hop, o score é multiplicado por <code>α = 0.85</code> e dividido pelo grau. Após 3 hops, o score acumulado de qualquer caminho já é menor que <code>0.01</code> — o limiar de ruído (<code>PPR_MIN_SCORE</code>).</p><h3 id="mecanismo-2-atenuacao-exponencial-temporal" tabindex="-1">Mecanismo 2: Atenuação exponencial temporal <a class="header-anchor" href="#mecanismo-2-atenuacao-exponencial-temporal" aria-label="Permalink to &quot;Mecanismo 2: Atenuação exponencial temporal&quot;">​</a></h3><p>O segundo mecanismo está no fator <code>exp(-0.05 · Δt / 86400)</code> em <code>main.rs:826</code>.</p><p>Para uma aresta com <code>Δt = 1 dia</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exp(-0.05 / 86400) ≈ exp(-5.79 · 10⁻⁷) ≈ 0.9999994</span></span></code></pre></div><p>Para <code>Δt = 30 dias</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exp(-0.05 · 30 / 86400) ≈ exp(-1.737 · 10⁻²) ≈ 0.9828</span></span></code></pre></div><p>Para <code>Δt = 90 dias</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exp(-0.05 · 90 / 86400) ≈ exp(-5.21 · 10⁻²) ≈ 0.949</span></span></code></pre></div><p>O decaimento é muito lento no curto prazo. Mas o efeito cumulativo ao longo de hops é significativo: cada aresta com mais de ~20 dias de idade reduz a condutância em ~5% por hop.</p><p>O ponto não é apenas o decaimento absoluto, mas o <strong>filtro dinâmico</strong>: arestas antigas transferem tão pouca condutância que seus vizinhos não sobrevivem ao limiar <code>PPR_MIN_SCORE = 0.01</code> após 3 hops. O grafo efetivo de difusão é muito menor que o grafo completo.</p><h3 id="mecanismo-3-retencao-por-limiar-de-score" tabindex="-1">Mecanismo 3: Retenção por limiar de score <a class="header-anchor" href="#mecanismo-3-retencao-por-limiar-de-score" aria-label="Permalink to &quot;Mecanismo 3: Retenção por limiar de score&quot;">​</a></h3><p>O terceiro mecanismo está em <code>main.rs:866</code>:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">next</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">retain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">_, v</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PPR_MIN_SCORE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Após cada hop, todos os nós com score menor que <code>0.01</code> são descartados da distribuição. Isso tem dois efeitos:</p><ol><li><strong>Poda do espaço de estados</strong>: o número de nós ativos após cada hop é bounded por <code>n / 0.01</code> onde <code>n</code> é a soma dos scores iniciais — ou seja, no máximo ~100 nós por semente ativa.</li><li><strong>Eliminação de paths de baixa relevância</strong>: qualquer caminho que acumule menos que <code>0.01</code> de score total é cortado. Como o score de um caminho de comprimento <code>k</code> é aproximadamente <code>s₀ · (α · w_avg)^k</code>, um caminho precisa de <code>w_avg</code> suficientemente alta para sobreviver 3 hops.</li></ol><p>Juntos, esses três mecanismos garantem que o espaço de busca após 3 hops seja <code>O(n · d²)</code> com um fator de poda que elimina nós de baixa relevância em cada camada. O sistema nunca precisa enumerar todos os caminhos — ele mantém apenas a distribuição de score por nó.</p><hr><h2 id="_5-por-que-a-dimensao-infinita-de-hilbert-nunca-e-computada-explicitamente" tabindex="-1">5. Por que a dimensão infinita de Hilbert nunca é computada explicitamente <a class="header-anchor" href="#_5-por-que-a-dimensao-infinita-de-hilbert-nunca-e-computada-explicitamente" aria-label="Permalink to &quot;5. Por que a dimensão infinita de Hilbert nunca é computada explicitamente&quot;">​</a></h2><p>A <code>GEOMETRIA_DE_FLUXO_T3.md</code> menciona que T3 funciona como espaço expressivo de incidência local. O <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code> define o Hamiltonian sobre vetores de dimensão <code>N = 768</code> (para <code>nomic-embed-text</code>).</p><p>Uma pergunta que poderia surgir: o sistema precisa computar algo no espaço de Hilbert de dimensão infinita?</p><p>A resposta é não, e a razão está no fato de que o sistema opera sobre <strong>representações discretas</strong>.</p><p>O Hamiltonian <code>H(V_s, V_t, T, δ, w, ℓ_s, ℓ_t)</code> é definido sobre vetores <code>V_s, V_t ∈ ℝ^N</code>. Cada nó do grafo tem um embedding de dimensão fixa <code>N = 768</code>. A difusão opera sobre os <strong>scores nodais</strong> — escalares — não sobre os embeddings.</p><p>O espaço de Hilbert de dimensão infinita seria relevante se estivéssemos:</p><ul><li>Fazendo kernel methods sobre o espaço de features contínuas</li><li>Resolvendo problemas de otimização variacional no espaço de funções</li><li>ComputandoSimilaridade em espaços com product dot infinito</li></ul><p>Mas o NEXUS não faz nada disso. Ele:</p><ol><li>Reduz a query a um conjunto de sementes (via T3, que usa dot product no espaço de embeddings)</li><li>Propaga scores escalares sobre o grafo (via T4, que usa Random Walk com condutância)</li><li>Hidrata conteúdo dos nós selecionados (via T2)</li></ol><p>A dimensão <code>N = 768</code> aparece apenas no cálculo do stress da aresta (Hamiltonian). Uma vez que o stress é computado e persistido como peso da aresta, a dimensão do embedding não é mais usada na difusão.</p><p><strong>Em resumo</strong>: o sistema discretiza o problema no nível do grafo. Os embeddings de alta dimensionalidade são usados apenas para computar pesos de aresta uma única vez (offline, no momento da criação da aresta). A difusão é completamente tractable porque opera sobre escalares.</p><hr><h2 id="_6-horizonte-limitado-versus-convergencia-ao-equilibrio" tabindex="-1">6. Horizonte limitado versus convergência ao equilíbrio <a class="header-anchor" href="#_6-horizonte-limitado-versus-convergencia-ao-equilibrio" aria-label="Permalink to &quot;6. Horizonte limitado versus convergência ao equilíbrio&quot;">​</a></h2><p>Há uma distinção importante entre o que o sistema faz e o que aconteceria se deixássemos o Random Walk rodar até o equilíbrio.</p><h3 id="o-que-o-sistema-faz-horizonte-limitado" tabindex="-1">O que o sistema faz: horizonte limitado <a class="header-anchor" href="#o-que-o-sistema-faz-horizonte-limitado" aria-label="Permalink to &quot;O que o sistema faz: horizonte limitado&quot;">​</a></h3><p>O sistema executa <code>PPR_MAX_HOPS = 3</code> iterações fixas. Isso é um <strong>horizonte limitado</strong> (bounded horizon). A distribuição de score após 3 hops é:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>s_3 = P³ · s_0</span></span></code></pre></div><p>Onde <code>P</code> é a matriz de transição do Random Walk e <code>s_0</code> é a distribuição inicial (sementes do Qdrant).</p><p>O horizonte limitado tem uma propriedade importante: ele preserva <strong>localidade temporal</strong>. Nós que são próximos às sementes em termos de hops recebem mais score do que nós que são distantes. Isso é exatamente o que queremos para montagem de contexto: o contexto relevante tende a estar perto das sementes semânticas.</p><h3 id="o-que-aconteceria-com-convergencia-de-equilibrio" tabindex="-1">O que aconteceria com convergência de equilíbrio <a class="header-anchor" href="#o-que-aconteceria-com-convergencia-de-equilibrio" aria-label="Permalink to &quot;O que aconteceria com convergência de equilíbrio&quot;">​</a></h3><p>Se deixássemos o Random Walk rodar até a distribuição estacionária (<code>k → ∞</code>), teríamos:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>s* = lim_{k→∞} P^k · s_0 = π</span></span></code></pre></div><p>Onde <code>π</code> é o stationary distribution — que para um grafo não-direcionado é proporcional ao grau do nó. Nesse caso, <strong>todos os nós seriam ranqueados principalmente pelo seu grau</strong>, não pela sua relevância para a query.</p><p>A <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code> discute a convergência de PPR em grafos direcionados (§4.1). Em grafos direcionados, a distribuição estacionária pode não ser única se houver múltiplas componentes fortemente conectadas. A convergência de PPR no grafo NEXUS direcionado é uma questão em aberto (Conjectura 9.1 no documento).</p><h3 id="por-que-horizonte-limitado-e-a-escolha-certa" tabindex="-1">Por que horizonte limitado é a escolha certa <a class="header-anchor" href="#por-que-horizonte-limitado-e-a-escolha-certa" aria-label="Permalink to &quot;Por que horizonte limitado é a escolha certa&quot;">​</a></h3><p>Para montagem de contexto, não queremos convergência de equilíbrio. Queremos:</p><ol><li><strong>Localidade</strong>: contexto que está topologicamente próximo das sementes</li><li><strong>Recência</strong>: arestas antigas transferem menos score (via decaimento temporal)</li><li><strong>Direcionalidade</strong>: o grafo é dirigido, então o score flui ao longo de relações específicas</li></ol><p>Um horizonte fixo de 3 hops garante que o contexto gerado seja uma <strong>vizinhança expandida</strong> das sementes, não o resultado de um processo de relaxamento global. O limite de 3 não é arbitrário — ele reflete o ponto onde o score acumulado de qualquer caminho adicional cai abaixo do limiar de ruído.</p><p><strong>Contraste com PageRank tradicional</strong>: PageRank tradicional sem restart (<code>α = 0</code>) converge para a distribuição estacionária, que é dominada pelo grau. PPR com restart (<code>α &amp;gt; 0</code>) converge para uma distribuição que é uma interpolação entre a distribuição estacionária e a distribuição de restart. O sistema NEXUS nem siquiera converge — ele para após um número fixo de hops.</p><hr><h2 id="_7-sintese-a-arquitetura-de-difusao-limitada" tabindex="-1">7. Síntese: a arquitetura de difusão limitada <a class="header-anchor" href="#_7-sintese-a-arquitetura-de-difusao-limitada" aria-label="Permalink to &quot;7. Síntese: a arquitetura de difusão limitada&quot;">​</a></h2><p>O mecanismo de difusão do T4 pode ser descrito em uma frase: <strong>um Random Walk com 3 hops, onde cada aresta tem condutância dependente de idade e o score de cada nó é redistribuído proporcionalmente ao grau, com poda de limiar</strong>.</p><p>As três perguntas que este documento responde são:</p><ol><li><p><strong>O que <code>w_q(e)</code> representa?</strong> Condutância, não trabalho. É a capacidade de transferência de relevância, não energia acumulada.</p></li><li><p><strong>Por que não há explosão combinatória?</strong> Três mecanismos ortogonais: horizonte fixo de 3 hops, atenuação temporal exponencial, e poda por limiar de score. Juntos, eles garantem que o espaço de busca efectivo seja <code>O(n · d²)</code> com fator de poda por camada.</p></li><li><p><strong>Por que a dimensão de Hilbert não importa?</strong> Porque o sistema discretiza no nível do grafo. Embeddings de alta dimensão são usados apenas para computar pesos de aresta offline. A difusão opera sobre escalares.</p></li></ol><p>Este documento complementa a <code>GEOMETRIA_DE_FLUXO_T3.md</code> (que define o que é difusão conceitualmente) e a <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code> (que define como o stress é calculado). Juntos, eles explicam: o que é difusão, como ela é pesada, e por que ela termina em tempo finito e útil.</p><hr><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>Definição de condutância em Random Walk: <code>main.rs:825-827</code></li><li>Fórmula de fluxo por aresta: <code>main.rs:855-860</code></li><li>Constantes de difusão (PPR_ALPHA, PPR_MAX_HOPS, PPR_MIN_SCORE): <code>main.rs:23-25</code></li><li>Horizonte de hops: <code>main.rs:812</code></li><li>Retenção por limiar: <code>main.rs:866</code></li><li>Formulação de caminho em <code>GEOMETRIA_DE_FLUXO_T3.md</code>: <code>J(γ) = Σ_{e ∈ γ} w_q(e)</code></li><li>Hamiltonian formal em <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code>: <code>H = max(0, ||V_t - T ⊙ V_s||² / N - δ) · √(M_s · M_t) · w</code></li><li>Discussão de convergência PPR em grafo dirigido: <code>FORMAL_ANALYSIS_HAMILTONIAN.md</code> §4.1</li></ul>`,108)])])}const u=e(n,[["render",t]]);export{m as __pageData,u as default};
